# --- Session Management Package ---
package Session;

sub new {
    my ($class, %opts) = @_;
    my $self = bless {
        session_dir    => $opts{session_dir}    || $SESSION_DIR,
        session_prefix => $opts{session_prefix} || $SESSION_PREFIX,
        session_expire => $opts{session_expire} || $SESSION_EXPIRE,
        cookie_name    => $opts{cookie_name}    || $COOKIE_NAME,
        session_id     => undef,
        data           => {},
        is_new         => 0,
        cgi            => $opts{cgi} || CGI->new(),
    }, $class;

    $self->_init();
    return $self;
}

sub _init {
    my ($self) = @_;

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch() || ();
    my $cookie  = $cookies{ $self->{cookie_name} };
    my $sid     = $cookie ? $cookie->value : undef;

    if ($sid && $self->_validate_session_id($sid) && $self->_session_file_exists($sid)) {
        # Load existing session
        $self->{session_id} = $sid;
        $self->_load();

        # Check if session has expired
        if ($self->_is_expired()) {
            $self->destroy();
            $self->_create_new_session();
        } else {
            # Update last access time
            $self->{data}{_last_access} = time();
            $self->_save();
        }
    } else {
        # Create new session
        $self->_create_new_session();
    }
}

sub _validate_session_id {
    my ($self, $sid) = @_;
    # Only allow hex characters (SHA-256 output) to prevent path traversal
    return ($sid && $sid =~ /^[a-f0-9]{64}$/);
}

sub _generate_session_id {
    my ($self) = @_;
    my $random_data = join('', map { chr(int(rand(256))) } 1..32);
    my $sid = Digest::SHA::sha256_hex($random_data . time() . $$ . rand());
    return $sid;
}

sub _session_file_path {
    my ($self, $sid) = @_;
    $sid ||= $self->{session_id};
    return File::Spec->catfile($self->{session_dir}, $self->{session_prefix} . $sid);
}

sub _session_file_exists {
    my ($self, $sid) = @_;
    return -e $self->_session_file_path($sid);
}

sub _create_new_session {
    my ($self) = @_;

    my $sid;
    # Ensure unique session ID
    do {
        $sid = $self->_generate_session_id();
    } while ($self->_session_file_exists($sid));

    $self->{session_id} = $sid;
    $self->{is_new}     = 1;
    $self->{data}       = {
        _created     => time(),
        _last_access => time(),
    };

    $self->_save();
}

sub _load {
    my ($self) = @_;
    my $file = $self->_session_file_path();

    eval {
        $self->{data} = lock_retrieve($file);
    };
    if ($@) {
        warn "Failed to load session file '$file': $@";
        $self->{data} = {};
        $self->_create_new_session();
    }
}

sub _save {
    my ($self) = @_;
    my $file = $self->_session_file_path();

    eval {
        lock_nstore($self->{data}, $file);
        chmod 0600, $file;  # Restrict permissions
    };
    if ($@) {
        warn "Failed to save session file '$file': $@";
    }
}

sub _is_expired {
    my ($self) = @_;
    my $last_access = $self->{data}{_last_access} || 0;
    return (time() - $last_access) > $self->{session_expire};
}

# --- Public API ---

sub id {
    my ($self) = @_;
    return $self->{session_id};
}

sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

sub get {
    my ($self, $key) = @_;
    return $self->{data}{$key};
}

sub set {
    my ($self, $key, $value) = @_;
    $self->{data}{$key} = $value;
    $self->_save();
    return $value;
}

sub delete {
    my ($self, $key) = @_;
    my $val = delete $self->{data}{$key};
    $self->_save();
    return $val;
}

sub keys {
    my ($self) = @_;
    return grep { !/^_/ } CORE::keys %{ $self->{data} };
}

sub clear {
    my ($self) = @_;
    my $created = $self->{data}{_created};
    $self->{data} = {
        _created     => $created,
        _last_access => time(),
    };
    $self->_save();
}

sub destroy {
    my ($self) = @_;
    my $file = $self->_session_file_path();
    unlink $file if -e $file;
    $self->{data} = {};
    $self->{session_id} = undef;
}

sub cookie {
    my ($self, %opts) = @_;
    return CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id},
        -expires  => '+' . $self->{session_expire} . 's',
        -path     => $opts{path}     || '/',
        -secure   => $opts{secure}   || 0,
        -httponly  => defined $opts{httponly} ? $opts{httponly} : 1,
        -samesite => $opts{samesite} || 'Strict',
    );
}

sub expire_cookie {
    my ($self) = @_;
    return CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => '',
        -expires  => '-1d',
        -path     => '/',
        -httponly  => 1,
    );
}

# Class method to clean up expired sessions
sub cleanup_expired {
    my ($class, %opts) = @_;
    my $dir    = $opts{session_dir}    || $SESSION_DIR;
    my $prefix = $opts{session_prefix} || $SESSION_PREFIX;
    my $expire = $opts{session_expire} || $SESSION_EXPIRE;
    my $count  = 0;

    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory '$dir': $!";
        return 0;
    };

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /^\Q$prefix\E[a-f0-9]{64}$/;
        my $filepath = File::Spec->catfile($dir, $entry);

        eval {
            my $data = retrieve($filepath);
            if ($data && ref $data eq 'HASH') {
                my $last_access = $data->{_last_access} || 0;
                if ((time() - $last_access) > $expire) {
                    unlink $filepath;
                    $count++;
                }
            }
        };
        if ($@) {
            # Corrupted session file, remove it
            unlink $filepath;
            $count++;
        }
    }
    closedir($dh);

    return $count;
}

